/*
	Name:
		Component Radio

	Description:
		Displays a radio form field.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		name
			Type: string
			Values: Any string
			Default: A random unique ID
			Description: Set the name attribute of the radio input elements (e.g. <input name='XXX'>)

		state
			Type: string
			Values: 'normal', 'success', 'error'
			Default: ''
			Description: Set the visual state of this component.

		disabled
			Type: boolean
			Values: true, false
			Default: false
			Description: Disable the field.

		label
			Type: string
			Values: Any string
			Default: ''
			Description: Display a field label.

		value
			Type: string
			Values: Any string
			Default: ''
			Description: Define which option is selected by its "value".

		options
			Type: Array
			Values: An array of objects which define the options.
			Default: ''
			Description: Setup the radio options with an array of objects. Example:
			[
				{
					// The label
					label:  'First option',

					// The value
					value:  'first-option',

					// Add helper text to this option
					helperText: 'Helper text'
				},
				...
			]

		...rest
			All other props are passed to <div>.
*/



/* Config
---------------------------------------------------------------------------------------------------- */
"use client";



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import Text from '../../typography/text';
import Icon from '../../icon';
import styles from './style.module.css';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedOptionsObject = {
	label: string,
	value: string,
	helperText?: string
};

type typedProps = {
	id?: string,
	className?: string,
	name?: string,
	state?: 'normal' | 'success' | 'error',
	disabled?: boolean,
	label?: string,
	value?: string,
	options?: Array<typedOptionsObject>
} & React.ComponentProps<'div'>;

function Radio({
	id = '',
	className = '',
	name = '',
	state = 'normal',
	disabled = false,
	label = '',
	value = '',
	options = [],

	// Support passing in event listeners from the parent
	// This ensures we don't override these as they're also used within this component
	onChange = () => {},

	...rest
}: typedProps) {
	/* If there's no name prop generate a unique id
	-------------------------------------------------- */
	const uniqueId = React.useId();
	if (!name) {
		name = uniqueId;
	}


	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_radio, className];


	/* Label
	-------------------------------------------------- */
	let labelOutput: React.ReactNode;
	if (label) {
		labelOutput = (
			<div className={styles.label}>
				<Text size='s' responsive={false} inheritWeight={true}>{label}</Text>
			</div>
		);
	}


	/* Error text
	-------------------------------------------------- */
	const errorTextOutput = (
		<div className={styles.errorText}>
			<Text size='xs'>Error text</Text>
		</div>
	);


	/* On change of the <input> element
	-------------------------------------------------- */
	function handleChange(event: React.ChangeEvent<HTMLInputElement>) {
		setSelectedState(event.currentTarget.value);

		// Also call the event handler that could be passed in from the parent
		onChange(event);
	}


	/* Options
	-------------------------------------------------- */
	// Create the selected state (starting with the default selected option)
	const [selectedState, setSelectedState] = React.useState(value);

	// Output the options
	const optionsOutput = options.map((option, index) => {
		// Helper text
		let helperTextOutput: React.ReactNode;
		if (option.helperText) {
			helperTextOutput = (
				<div className={styles.helperText}>
					<Text size='xs'>{option.helperText}</Text>
				</div>
			);
		}

		// Selected
		let optionSelected = false;
		if (option.value === selectedState) {
			optionSelected = true;
		}

		return (
			<div className={styles.option} key={index}>
				{/* Field */}
				<div className={styles.checkboxContainer} data-selected={optionSelected}>
					<input
						type='radio'
						disabled={disabled}
						name={name}
						value={option.value}
						id={name + '_' + index}
						checked={optionSelected}
						onChange={handleChange}
					/>
					<Icon name='tick-02' size='xxs' style='stroke' type='sharp' strokeWidth={4} className={styles.icon} />
				</div>

				<div className={styles.textContainer}>
					<label htmlFor={name + '_' + index}>
						<Text size='s' responsive={false} inheritWeight={true}>{option.label}</Text>
					</label>

					{helperTextOutput}
				</div>
			</div>
		);
	});


	/* Output the component
	-------------------------------------------------- */
	return (
		<div className={classes.join(' ')} id={id} data-state={state} data-disabled={disabled} {...rest}>
			{/* Label */}
			{labelOutput}

			{/* Options */}
			<fieldset className={styles.options}>
				{optionsOutput}
			</fieldset>

			{/* Error text */}
			{errorTextOutput}
		</div>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default Radio;

// Types
export type { typedProps as RadioTypes };
