/*
	Name:
		Component Scrollbar

	Description:
		Displays a styled Scrollbar.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		...rest
			All other props are passed to <div>.
*/



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import styles from './style.module.css';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedProps = {
	id?: string,
	className?: string,
	children?: React.ReactNode
} & React.ComponentProps<'div'>;

function Scrollbar({
	id = '',
	className = '',
	children,
	...rest
}: typedProps) {
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_scrollbar, className];


	/* Output the component
	-------------------------------------------------- */
	return (
		<div className={classes.join(' ')} id={id} {...rest}>
			{children}
		</div>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default Scrollbar;

// Types
export type { typedProps as ScrollbarTypes };
