/*
	Name:
		Component H4

	Description:
		Displays a Heading 4.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		gap
			Type: boolean
			Values: true, false
			Default: false
			Description: Add a default gap (padding) below this component.

		responsive
			Type: boolean
			Values: true, false
			Default: true
			Description: Make this component responsive.

		inheritWeight
			Type: boolean
			Values: true, false
			Default: false
			Description: Inherit the font weight from the parent element.

		useTag
			Type: string
			Values: 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'p', 'span', 'div'
			Default: 'h4'
			Description: Use a different HTML tag for this text element.

		...rest
			All other props are passed to <h4> (or the tag you passed in with the "useTag" prop).
*/



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import styles from './style.module.css';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedProps = {
	id?: string,
	className?: string,
	gap?: boolean,
	responsive?: boolean,
	inheritWeight?: boolean,
	useTag?: 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6' | 'p' | 'span' | 'div',
	children?: React.ReactNode
} & React.ComponentProps<'h1'> & React.ComponentProps<'h2'> & React.ComponentProps<'h3'> & React.ComponentProps<'h4'> & React.ComponentProps<'h5'> & React.ComponentProps<'h6'> & React.ComponentProps<'p'> & React.ComponentProps<'span'> & React.ComponentProps<'div'>;

function H4({
	id = '',
	className = '',
	gap = false,
	responsive = true,
	inheritWeight = false,
	useTag = 'h4',
	children,
	...rest
}: typedProps) {
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_h4, className];

	// Gap
	if (gap) {
		classes.push(styles.gap);
	}

	// Responsive
	if (responsive) {
		classes.push(styles.responsive);

		// Add a responsive gap
		if (gap) {
			classes.push(styles.responsive_gap);
		}
	}

	// Inherit weight
	if (inheritWeight) {
		classes.push(styles.inheritWeight);
	}

	// Use a custom HTML tag
	const TagName = useTag;


	/* Output the component
	-------------------------------------------------- */
	return (
		<TagName className={classes.join(' ')} id={id} {...rest}>
			{children}
		</TagName>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default H4;

// Types
export type { typedProps as H4Types };
