/*
	Name:
		Component Date Picker

	Description:
		Displays a date picker form field.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		name
			Type: string
			Values: Any string
			Default: A random unique ID
			Description: Set the name attribute of this input (e.g. <input name='XXX'>)

		state
			Type: string
			Values: 'normal', 'success', 'error'
			Default: ''
			Description: Set the visual state of this component.

		disabled
			Type: boolean
			Values: true, false
			Default: false
			Description: Disable the field.

		label
			Type: string
			Values: Any string
			Default: ''
			Description: Display a field label.

		helperText
			Type: string
			Values: Any string
			Default: ''
			Description: Display helper text below this field.

		date
			Type: string
			Values: A date string in the following format: DD/MM/YYYY
			Default: ''
			Description: Set the date of this field.

		...rest
			All other props are passed to <input>.
*/



/* Config
---------------------------------------------------------------------------------------------------- */
"use client";



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import dayjs, { Dayjs } from "dayjs";
import { DatePicker as MUIDatePicker } from '@mui/x-date-pickers';
import { LocalizationProvider } from '@mui/x-date-pickers/LocalizationProvider';
import { AdapterDayjs } from '@mui/x-date-pickers/AdapterDayjs';
import Text from '../../typography/text';
import Icon from '../../icon';
import styles from './style.module.css';
import './mui_datePicker.css';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedProps = {
	id?: string,
	className?: string,
	name?: string,
	state?: 'normal' | 'success' | 'error',
	disabled?: boolean,
	label?: string,
	helperText?: string,
	date?: string
} & React.ComponentProps<'input'>;

function DatePicker({
	id = '',
	className = '',
	name = '',
	state = 'normal',
	disabled = false,
	label = '',
	helperText = '',
	date = '',

	// Support passing in event listeners from the parent
	// This ensures we don't override these as they're also used within this component
	onBlur = () => {},
	onFocus = () => {},
	onChange = () => {},
	onKeyDown = () => {},

	...rest
}: typedProps) {
	/* Functionality
	---------------------------------------------------------------------------------------------------- */
	/* Create state
	-------------------------------------------------- */
	// Focus state (true, false)
	const [focusState, setFocusState] = React.useState(false);

	// Initial field value (used to restore the value on escape keypress)
	const [initialValueState, setInitialValueState] = React.useState('');

	// Value state for our <input> field
	const [valueState, setValueState] = React.useState(date);

	// Value state for Material UI <input> field
	let formattedDate: Dayjs | null = dayjs(date, 'DD/MM/YYYY');
	if (formattedDate && !formattedDate.isValid()) {
		formattedDate = null;
	}
	const [mui_valueState, mui_setValueState] = React.useState(formattedDate);


	/* Create refs to target DOM elements
	-------------------------------------------------- */
	// Our HTML <input> field
	const fieldRef = React.useRef<HTMLInputElement>(null);

	// Material UI date picker
	const muiDatePickerRef = React.useRef<HTMLInputElement>(null);


	/* If there's no name prop generate a unique id
	-------------------------------------------------- */
	const uniqueId = React.useId();
	if (!name) {
		name = uniqueId;
	}


	/* Support escape keypress to restore initial field value
	-------------------------------------------------- */
	// Save initial value (on focus)
	function saveInitialValue() {
		// Get the value of the field
		let localValue = fieldRef?.current?.value;

		// Make sure it's a string
		if (typeof localValue !== 'string') {
			localValue = '';
		}

		// Set the initial value state variable
		setInitialValueState(localValue);
	}

	// Check for the escape keypress (on key down)
	function handleKeyDown(event: React.KeyboardEvent<HTMLInputElement>) {
		// Target the field
		const field = fieldRef.current;

		// Make sure the field exists
		if (!field) {
			return;
		}

		// If escape was pressed
		if (event.key === "Escape") {
			// Restore the initial value
			field.value = initialValueState;

			// Blur the field
			field.blur();
		}

		// Also call the event handler that could be passed in from the parent
		onKeyDown(event);
	}


	/* Show date picker (on click of date picker icon)
	-------------------------------------------------- */
	function showDatePicker() {
		const button = muiDatePickerRef?.current?.querySelector('button');

		if (button) {
			button.click();
		}
		else {
			muiDatePickerRef?.current?.click();
		}
	}


	/* On change of our field
	-------------------------------------------------- */
	function handleChange(event: React.ChangeEvent<HTMLInputElement>) {
		// Get our input field's value
		const value = event.target.value;

		// Get the field value as a "Dayjs" style date
		const dateValue: Dayjs | null = dayjs(value, 'DD/MM/YYYY');

		// If it's valid
		if (dateValue.isValid()) {
			// Set the value of the material ui field
			mui_setValueState(dateValue);
		}
		// Otherwise if it's invalid
		else {
			// Set the value of the material ui field to null
			mui_setValueState(null);
		}

		// Set the value of our input field (string)
		setValueState(value);

		// Also call the event handler that could be passed in from the parent
		onChange(event);
	}


	/* On blur of our field, automatically format the date for ease of use
	-------------------------------------------------- */
	function formatDate(event: React.ChangeEvent<HTMLInputElement>) {
		// Get our input field's value
		let value = event.target.value;

		// If there's a value
		if (value) {


			/* Entire date formatting
			------------------------- */
			// Replace dashes with slashes
			value = value.replace(/-/g, '/');

			// Replace dots with slashes
			value = value.replace(/\./g, '/');

			// Replace spaces with slashes
			value = value.replace(/ /g, '/');


			// If there's no slashes
			if (value.indexOf('/') === -1) {
				// If it's 4 digits long, add slashes
				if (value.length === 4) {
					const day = value.substr(0, 2);
					const month = value.substr(2, 2);

					value = day + '/' + month;
				}

				// If it's 6 digits long, add slashes
				if (value.length === 6) {
					const day = value.substr(0, 2);
					const month = value.substr(2, 2);
					const year = value.substr(4, 2);

					value = day + '/' + month + '/' + year;
				}

				// If it's 8 digits long, add slashes
				if (value.length === 6) {
					const day = value.substr(0, 2);
					const month = value.substr(2, 2);
					const year = value.substr(4, 4);

					value = day + '/' + month + '/' + year;
				}
			}


			// Split on slashes
			let bits = value.split('/');

			// If we've got 1 slash
			if (bits.length === 2) {
				// Add this year
				value = bits.join('/') + '/' + new Date().getFullYear();

				// Re-split on slashes
				bits = value.split('/');
			}

			// If we've got 2 slashes
			if (bits.length === 3) {
				/* Year formatting
				------------------------- */
				// If year is less than 0, make it 0000
				if (parseFloat(bits[2]) < 0) {
					bits[2] = '0000';
				}

				// If year is two digits long
				if (bits[2].length === 2) {
					// Add '20' if it's less than 50
					if (parseFloat(bits[2]) < 50) {
						bits[2] = '20' + bits[2];
					}
					// Add '19' if it's more than 50
					else {
						bits[2] = '19' + bits[2];
					}
				}


				/* Month formatting
				------------------------- */
				// If month is less than 1, make it 1
				if (parseFloat(bits[1]) < 1) {
					bits[1] = '01';
				}

				// If month is greater than 12, make it 12
				if (parseFloat(bits[1]) > 12) {
					bits[1] = '12';
				}

				// Add leading zero to month
				if (bits[1].length === 0) {
					bits[1] = '0' + bits[1];
				}


				/* Day formatting
				------------------------- */
				// If day is less than 1, make it 1
				if (parseFloat(bits[0]) < 1) {
					bits[0] = '01';
				}

				// Work out the last day of the month (taking into account leap years)
				let lastDayOfMonth = 30;
				if (
					parseFloat(bits[1]) === 1 ||
					parseFloat(bits[1]) === 3 ||
					parseFloat(bits[1]) === 5 ||
					parseFloat(bits[1]) === 7 ||
					parseFloat(bits[1]) === 8 ||
					parseFloat(bits[1]) === 10 ||
					parseFloat(bits[1]) === 12
				) {
					lastDayOfMonth = 31;
				}
				else if (parseFloat(bits[1]) === 2) {
					// Leap year (divisible by 4)
					if (parseFloat(bits[2]) % 4 === 0) {
						lastDayOfMonth = 29;
					}
					// Normal year
					else {
						lastDayOfMonth = 28;
					}
				}

				// If day is greater than last day of month
				if (parseFloat(bits[0]) > lastDayOfMonth) {
					bits[0] = lastDayOfMonth.toString();
				}

				// Add leading zero to day
				if (bits[0].length === 0) {
					bits[0] = '0' + bits[0];
				}


				/* Output the modified date
				------------------------- */
				value = bits.join('/');
			}
		}

		// Get the field value as a "Dayjs" style time
		const dateValue: Dayjs | null = dayjs(value, 'DD/MM/YYYY');

		// If it's valid
		if (dateValue.isValid()) {
			// Set the value of our input field (string)
			setValueState(dateValue.format('DD/MM/YYYY'));

			// Set the value of the material ui field
			mui_setValueState(dateValue);
		}
		// Otherwise if it's invalid
		else {
			// Set the value of our input field (string)
			setValueState('');

			// Set the value of the material ui field to null
			mui_setValueState(null);
		}
	}


	/* On change of the material ui field
	-------------------------------------------------- */
	function mui_handleChange(newDate: Dayjs | null) {
		// Set the value of the material ui field
		mui_setValueState(newDate);

		// Get the material ui's field value as a string
		let newDateString = '';
		if (newDate && newDate.isValid()) {
			newDateString = newDate.format('DD/MM/YYYY');
		}

		// Set the value of our input field (string)
		setValueState(newDateString);
	}


	/* On focus of the <input> element
	-------------------------------------------------- */
	function handleFocus(event: React.FocusEvent<HTMLInputElement>) {
		saveInitialValue();
		setFocusState(true);

		// Also call the event handler that could be passed in from the parent
		onFocus(event);
	}


	/* On blur of the <input> element
	-------------------------------------------------- */
	function handleBlur(event: React.FocusEvent<HTMLInputElement>) {
		setFocusState(false);
		formatDate(event);

		// Also call the event handler that could be passed in from the parent
		onBlur(event);
	}



	/* Layout
	---------------------------------------------------------------------------------------------------- */
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_datePicker, className];


	/* Label
	-------------------------------------------------- */
	let labelOutput: React.ReactNode;
	if (label) {
		labelOutput = (
			<div className={styles.label}>
				<Text size='s' responsive={false} inheritWeight={true}>{label}</Text>
			</div>
		);
	}


	/* Helper text
	-------------------------------------------------- */
	let helperTextOutput: React.ReactNode;
	if (helperText) {
		helperTextOutput = (
			<div className={styles.helperText}>
				<Text size='xs'>{helperText}</Text>
			</div>
		);
	}


	/* Error text
	-------------------------------------------------- */
	const errorTextOutput = (
		<div className={styles.errorText}>
			<Text size='xs'>Error text</Text>
		</div>
	);


	/* Output the component
	-------------------------------------------------- */
	return (
		<div className={classes.join(' ')} id={id} data-state={state} data-disabled={disabled}>
			{/* Label */}
			{labelOutput}

			<div className={styles.fieldContainer} data-focus={focusState} data-disabled={disabled}>
				{/* Material UI DatePicker */}
				<LocalizationProvider dateAdapter={AdapterDayjs} adapterLocale="en">
					<MUIDatePicker
						format='DD/MM/YYYY'
						disabled={disabled}
						value={mui_valueState}
						onChange={mui_handleChange}
						className={styles.muiField}
						ref={muiDatePickerRef}
						showDaysOutsideCurrentMonth={true}
					/>
				</LocalizationProvider>

				{/* Field */}
				<input
					name={name}
					ref={fieldRef}
					disabled={disabled}
					onBlur={handleBlur}
					onFocus={handleFocus}
					onChange={handleChange}
					onKeyDown={handleKeyDown}
					value={valueState}
					{...rest}
				/>

				{/* Date picker icon */}
				<button className={styles.pickerIcon} onClick={showDatePicker}>
					<Icon name='calendar-03' size='s' style='solid' type='sharp' responsive={false} />
				</button>
			</div>

			{/* Error text */}
			{errorTextOutput}

			{/* Helper text */}
			{helperTextOutput}
		</div>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default DatePicker;

// Types
export type { typedProps as DatePickerTypes };
