/*
	Name:
		Component Tooltip

	Description:
		Displays an Tooltip using Material UI.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		title
			Type: string
			Values: Any string
			Default: ''
			Description: Define the text of the tooltip.

		...rest
			All props are passed to the <MUITooltip> (https://mui.com/material-ui/api/tooltip/).
*/



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import styles from './style.module.css';
import Text from '../typography/text';
import MUITooltip, { TooltipProps } from '@mui/material/Tooltip';
import './mui_tooltip.css';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedProps = {
	id?: string,
	className?: string,
	text?: string,
	children?: React.ReactNode
} & TooltipProps;

function Tooltip({
	id = '',
	className = '',
	title = '',
	children,
	...rest
}: typedProps) {
	/* Functionality
	---------------------------------------------------------------------------------------------------- */
	/* Create state to control when the tooltip is open
	-------------------------------------------------- */
	const [openState, setOpenState] = React.useState(false);


	/* Create refs to target the tooltip container
	-------------------------------------------------- */
	const containerRef = React.useRef<HTMLDivElement>(null);


	/* Are we using a touch device?
	-------------------------------------------------- */
	function isTouchDevice() {
		return ("ontouchstart" in document.documentElement);
	}


	/* On mouse over of the tooltip container
	-------------------------------------------------- */
	function handleMouseOver() {
		if (!isTouchDevice()) {
			setOpenState(true);
		}
	}


	/* On mouse out of the tooltip container
	-------------------------------------------------- */
	function handleMouseOut() {
		if (!isTouchDevice()) {
			setOpenState(false);
		}
	}


	/* On click of the window, show or hide the tooltip
	-------------------------------------------------- */
	function handleWindowClick(event: MouseEvent) {
		// Did we click inside the container?
		let isInContainer = false;
		if (containerRef.current) {
			const rect = containerRef.current.getBoundingClientRect();
			const { clientX, clientY } = event;

			isInContainer =
				clientX >= rect.left &&
				clientX <= rect.right &&
				clientY >= rect.top &&
				clientY <= rect.bottom;
		}

		// We clicked inside the container
		if (isInContainer) {
			// Open the tooltip
			setOpenState(true);
		}
		// We clicked outside the container
		else {
			// Hide the tooltip
			setOpenState(false);
		}
	}


	/* On mount and unmount
	-------------------------------------------------- */
	React.useEffect(() => {
		// Watch for window clicks (touch devices only)
		if (isTouchDevice()) {
			window.addEventListener('click', handleWindowClick);
		}

		return () => {
			// Stop watching for window clicks (touch devices only)
			if (isTouchDevice()) {
				window.removeEventListener('click', handleWindowClick);
			}
		};
	});



	/* Layout
	---------------------------------------------------------------------------------------------------- */
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_button, className];


	/* Wrap the title with our local typography
	-------------------------------------------------- */
	const wrappedTitle = <Text size='xs'>{title}</Text>;


	/* Ensure that children are wrapped inside a React Fragment
	-------------------------------------------------- */
	if (typeof children === 'string') {
		children = <>{children}</>;
	}


	/* Output the component
	-------------------------------------------------- */
	return (
		<MUITooltip
			arrow={true}
			title={wrappedTitle}
			open={openState}
			{...rest}
		>
			<div
				ref={containerRef}
				onMouseOver={handleMouseOver}
				onMouseOut={handleMouseOut}
				className={classes.join(' ')}
				id={id}
			>
				{children}
			</div>
		</MUITooltip>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default Tooltip;

// Types
export type { typedProps as TooltipTypes };
