/*
	Name:
		Component Modal

	Description:
		Displays a Modal.

		React must set the state in the parent where this modal is used and pass it down as props.

		Example usage:
			export default function examplePage() {
				// Create a state variable to manage the modal open state
				const [modalOpenState, setModalOpenState] = React.useState(false);

				return (
					// A button that opens the modal
					<button
						onClick={() => {
							setModalOpenState(true);
						}}
					>
						Click to open the modal
					</button>

					// Include the modal and pass down the state value / state setting function
					<Modal
						openState={modalOpenState}
						setOpenState={setModalOpenState}
						...
					>
						The modal content goes here
					</Modal>
				);
			};

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		openState
			Type: boolean
			Values: true / false
			Default: false
			Description: Is the modal open? Provide this as a React State variable from the parent where it's used.

		setOpenState
			Type: function
			Values: A React State setting function
			Default: false
			Description: The function which changes the open state. Provide this as a React State setting function from the parent where it's used.

		buttons
			Type: Array
			Values: An array of objects which define the buttons.
			Default: ''
			Description: Setup the buttons in the modal with an array of objects. Example:
			[
				{
					// The button type (primary, secondary, outline)
					type: 'primary',

					// The button text
					label: 'Submit',

					// The button href
					href: '#',

					// Should this button close the modal?
					closeModal: true
				},
				...
			]

		...rest
			All other props are passed to <div>.
*/



/* Config
---------------------------------------------------------------------------------------------------- */
"use client";



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import styles from './style.module.css';
import Icon from '../icon';
import Button from '../button';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedButtonsObject = {
	type: 'primary' | 'secondary' | 'outline',
	label: string,
	href: string,
	closeModal: boolean
};

type typedProps = {
	id?: string,
	openState?: boolean,
	setOpenState?: (arg: boolean) => void,
	buttons?: Array<typedButtonsObject>,
	className?: string,
	children?: React.ReactNode
} & React.ComponentProps<'div'>;

function Modal({
	id = '',
	className = '',
	openState = false,
	setOpenState = () => {},
	buttons = [],
	children,
	...rest
}: typedProps) {
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_modal, className];


	/* Close the modal
	-------------------------------------------------- */
	function closeModal(event?: React.MouseEvent) {
		// If the modal is open
		if (openState) {
			// Disable the button href default action for buttons or links that close the modal
			event?.preventDefault();
			event?.stopPropagation();

			// Close the modal
			setOpenState(false);
		}
	}


	/* Support escape keypress to close the modal
	-------------------------------------------------- */
	function handleKeyDown(event: KeyboardEvent) {
		if (event.key === "Escape") {
			closeModal();
		}
	}


	/* On mount and unmount
	-------------------------------------------------- */
	React.useEffect(() => {
		// Watch for window key presses
		window.addEventListener('keydown', handleKeyDown);

		return () => {
			// Stop watching for window key presses
			window.addEventListener('keydown', handleKeyDown);
		};
	});


	/* Create the buttons
	-------------------------------------------------- */
	const buttonsOutput = buttons.map((button, index) => {
		// If this button closes the modal, add an onClick to close the modal
		let buttonOnClick = () => {};
		if (button.closeModal) {
			buttonOnClick = closeModal;
		}

		// Output the button
		return (
			// This "key" attribute only exists to satisfy the requirements of React (we don't actually use it)
			<Button href={button.href} type={button.type} size='m' key={index} onClick={buttonOnClick}>{button.label}</Button>
		);
	});


	/* Output the component
	-------------------------------------------------- */
	return (
		<div className={classes.join(' ')} id={id} data-open={openState} {...rest}>
			{/* Overlay / dark background */}
			<div className={styles.overlay} onClick={closeModal} />

			{/* Modal */}
			<div className={styles.modal}>
				<button className={styles.closeButton} onClick={closeModal}><Icon name='cancel-01' size='s' strokeWidth={3} type='sharp' /></button>
				{children}
				<div className={styles.buttons}>{buttonsOutput}</div>
			</div>
		</div>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default Modal;

// Types
export type { typedProps as ModalTypes };
