/*
	Name:
		Component Pill

	Description:
		Displays a Pill.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		type
			Type: string
			Values: 'primary', 'secondary', 'info', 'success', 'warning', 'error'
			Default: 'primary'
			Description: Define the pill style.

		size
			Type: string
			Values: 'l', 'm', 's', 'xs'
			Default: 'm'
			Description: Define the pill size.

		...rest
			All other props are passed to <div>.
*/



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import styles from './style.module.css';
import Text from '../typography/text';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedProps = {
	id?: string,
	className?: string,
	type?: 'primary' | 'secondary' | 'info' | 'success' | 'warning' | 'error',
	size?: 'l' | 'm' | 's' | 'xs',
	children?: React.ReactNode
} & React.ComponentProps<'div'>;

function Pill({
	id = '',
	className = '',
	type = 'primary',
	size = 'm',
	children,
	...rest
}: typedProps) {
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_pill, className];

	// Type
	if (type) {
		classes.push(styles['type_' + type]);
	}

	// Size
	if (size) {
		classes.push(styles['size_' + size]);
	}


	/* Setup the text size (this exists as the mapping may change)
	-------------------------------------------------- */
	let textSize: 'l' | 'm' | 's' | 'xs';
	if (size === 'l') {
		textSize = 'l';
	}
	else if (size === 'm') {
		textSize = 'm';
	}
	else if (size === 's') {
		textSize = 's';
	}
	else {
		textSize = 'xs';
	}


	/* Output the component
	-------------------------------------------------- */
	return (
		<div className={classes.join(' ')} id={id} {...rest}>
			<Text size={textSize}>{children}</Text>
		</div>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default Pill;

// Types
export type { typedProps as PillTypes };
