/*
	Name:
		Component Breadcrumbs

	Description:
		Displays a Breadcrumbs.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		items
			Type: Array
			Values: An array of objects which define the breadcrumb items.
			Default: ''
			Description: Setup the items in the breadcrumbs with an array of objects. Example:
			[
				{
					// The label
					label: 'First breadcrumb',

					// The href (pass an empty string to make the breadcrumb not a link / not clickable)
					href: '/first-breadcrumb/'
				},
				...
			]

		...rest
			All other props are passed to <div>.
*/



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import styles from './style.module.css';
import Text from '../typography/text';
import Link from '../link';
import Icon from '../icon';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedItemsObject = {
	label: string,
	href: string
};

type typedProps = {
	id?: string,
	className?: string,
	items?: Array<typedItemsObject>
} & React.ComponentProps<'div'>;

function Breadcrumbs({
	id = '',
	className = '',
	items = [],
	...rest
}: typedProps) {
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_breadcrumbs, className];


	/* Output the component
	-------------------------------------------------- */
	return (
		<div className={classes.join(' ')} id={id} {...rest}>
			{/* Home icon */}
			<div className={styles.breadcrumb}>
				<Link href='/' className={styles.label} size='xs'><Icon className={styles.homeIcon} name='home-05' size='xs' type='sharp' /></Link>
				<div className={styles.divider}><Icon name='arrow-right-01' size='xxs' type='sharp' /></div>
			</div>

			{/* Breadcrumbs */}
			{
				items.map((item, index) => {
					let breadcrumb: React.ReactNode;

					// Without link
					if (item.href === '') {
						breadcrumb = <Text size='s' className={styles.label} >{item.label}</Text>;
					}
					// With link
					else {
						breadcrumb = <Link href={item.href} className={styles.label} size='s'>{item.label}</Link>;
					}

					// Add a divider (but not for the last item)
					let divider: React.ReactNode;
					if (index !== (items.length - 1)) {
						divider = <div className={styles.divider}><Icon name='arrow-right-01' size='xxs' type='sharp' /></div>;
					}

					// Return the breadcrumb and divider
					return (
						// This "key" attribute only exists to satisfy the requirements of React (we don't actually use it)
						<div className={styles.breadcrumb} key={index}>
							{breadcrumb}
							{divider}
						</div>
					);
				})
			}
		</div>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default Breadcrumbs;

// Types
export type { typedProps as BreadcrumbsTypes };
