/*
	Name:
		Component Notice

	Description:
		Displays a Notice.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		type
			Type: string
			Values: 'info', 'success', 'warning', 'error'
			Default: 'info'
			Description: Define the notice style.

		...rest
			All other props are passed to <div>.
*/



/* Config
---------------------------------------------------------------------------------------------------- */
"use client";



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import styles from './style.module.css';
import Text from '../typography/text';
import Icon from '../icon';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedProps = {
	id?: string,
	className?: string,
	type?: 'info' | 'success' | 'warning' | 'error',
	children?: React.ReactNode
} & React.ComponentProps<'div'>;

function Notice({
	id = '',
	className = '',
	type = 'info',
	children,
	...rest
}: typedProps) {
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_notice, className];

	// Type
	if (type) {
		classes.push(styles['type_' + type]);
	}


	/* Hidden state
	-------------------------------------------------- */
	const [hiddenState, sethiddenState] = React.useState(false);


	/* On click of the close button
	-------------------------------------------------- */
	function handleClick() {
		sethiddenState(true);
	}


	/* Define the icon
	-------------------------------------------------- */
	let iconName = 'information-circle';
	if (type === 'success') {
		iconName = 'checkmark-circle-02';
	}
	else if (type === 'warning') {
		iconName = 'alert-circle';
	}
	else if (type === 'error') {
		iconName = 'multiplication-sign-circle';
	}


	/* Output the component
	-------------------------------------------------- */
	return (
		<div className={classes.join(' ')} id={id} data-hidden={hiddenState} {...rest}>
			<Icon name={iconName} size='s' className={styles.icon} />
			<Text size='s' className={styles.text}>{children}</Text>
			<button className={styles.closeButton} onClick={handleClick}>
				<Icon name='multiplication-sign' size='s' type='sharp' />
			</button>
		</div>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default Notice;

// Types
export type { typedProps as NoticeTypes };
