/*
	Name:
		Component Expand Collapse Button

	Description:
		Displays an Expand Collapse Button.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		size
			Type: string
			Values: 'h1', 'h2', 'h3', 'h4', 'l', 'm', 's', 'xs'
			Default: 'l'
			Description: Define the size for the button.

		expanded
			Type: boolean
			Values: true, false
			Default: false
			Description: Is the button expanded?

		...rest
			All other props are passed to <button>.
*/



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import H1 from '../typography/h1';
import H2 from '../typography/h2';
import H3 from '../typography/h3';
import H4 from '../typography/h4';
import Text from '../typography/text';
import Image from 'next/image';
import styles from './style.module.css';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedProps = {
	id?: string,
	className?: string,
	size?: 'h1' | 'h2' | 'h3' | 'h4' | 'l' | 'm' | 's' | 'xs',
	href?: string,
	target?: '_blank' | '_self' | '_parent' | '_top',
	expanded?: boolean
} & React.ComponentProps<'button'>;

function ExpandCollapseButton({
	id = '',
	className = '',
	size = 'l',
	expanded = false,

	// Support passing in event listeners from the parent
	// This ensures we don't override these as they're also used within this component
	onClick = () => {},

	...rest
}: typedProps) {
	/* Functionality
	---------------------------------------------------------------------------------------------------- */
	/* Create state
	-------------------------------------------------- */
	// Expanded state (true, false)
	const [expandedState, setExpandedState] = React.useState(expanded);


	/* Toggle expanded / collapsed on click
	-------------------------------------------------- */
	function handleClick(event: React.MouseEvent<HTMLButtonElement>) {
		// Toggle expanded state
		setExpandedState(!expandedState);

		// Also call the event handler that could be passed in from the parent
		onClick(event);
	}



	/* Layout
	---------------------------------------------------------------------------------------------------- */
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_expandCollapseButton, className];

	// Size
	if (size) {
		classes.push(styles['size_' + size]);
	}

	// Add an expanded class if required
	if (expandedState) {
		classes.push(styles.expanded);
	}


	/* Define the label
	-------------------------------------------------- */
	let label = 'Show more';
	if (expandedState) {
		label = 'Show less';
	}


	/* Define the arrow icon (we use a custom SVG here - it comes from the "huge icon" pack but has the whitespace removed - this is required for accurate styling in the CSS)
	-------------------------------------------------- */
	const icon = <Image src='/img/icons/down-arrow-blue.svg' alt='' width={20} height={34} className={styles.arrow} />;


	/* Define the text size
	-------------------------------------------------- */
	let text: React.ReactNode;
	if (size === 'h1') {
		text = <H1>{label}</H1>;
	}
	else if (size === 'h2') {
		text = <H2>{label}</H2>;
	}
	else if (size === 'h3') {
		text = <H3>{label}</H3>;
	}
	else if (size === 'h4') {
		text = <H4>{label}</H4>;
	}
	else {
		text = <Text size={size} inheritWeight={true}>{label}</Text>;
	}


	/* Output the component
	-------------------------------------------------- */
	return (
		<button className={classes.join(' ')} id={id} onClick={handleClick} {...rest}>
			{text}
			{icon}
		</button>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default ExpandCollapseButton;

// Types
export type { typedProps as ExpandCollapseButtonTypes };
