/*
	Name:
		Component Arrow Button

	Description:
		Displays an Arrow Button.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		arrowPosition
			Type: string
			Values: 'left', 'right'
			Default: 'left'
			Description: Define the position of the arrow icon.

		size
			Type: string
			Values: 'h1', 'h2', 'h3', 'h4', 'l', 'm', 's', 'xs'
			Default: 'l'
			Description: Define the size for the arrow button.

		href
			Type: string
			Values: Any link
			Default: ''
			Description: Define the href for the arrow button.

		target
			Type: string
			Values: '_blank', '_self', '_parent', '_top'
			Default: '_self'
			Description: Define the target for the arrow button.

		...rest
			All other props are passed to <NextLink>.
*/



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import NextLink, { LinkProps } from 'next/link';
import H1 from '../typography/h1';
import H2 from '../typography/h2';
import H3 from '../typography/h3';
import H4 from '../typography/h4';
import Text from '../typography/text';
import Image from 'next/image';
import styles from './style.module.css';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedProps = {
	id?: string,
	className?: string,
	arrowPosition?: 'left' | 'right',
	size?: 'h1' | 'h2' | 'h3' | 'h4' | 'l' | 'm' | 's' | 'xs',
	href?: string,
	target?: '_blank' | '_self' | '_parent' | '_top',
	children?: React.ReactNode
} & LinkProps;

function ArrowButton({
	id = '',
	className = '',
	arrowPosition = 'left',
	size = 'l',
	href = '',
	target = '_self',
	children,

	// Support passing in event listeners from the parent
	// This ensures we don't override these as they're also used within this component
	onClick = () => {},

	...rest
}: typedProps) {
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_arrowButton, className];

	// Arrow position
	if (arrowPosition) {
		classes.push(styles['arrowPosition_' + arrowPosition]);
	}

	// Size
	if (size) {
		classes.push(styles['size_' + size]);
	}


	/* Define the arrow icon (we use a custom SVG here - it comes from the "huge icon" pack but has the whitespace removed - this is required for accurate styling in the CSS)
	-------------------------------------------------- */
	const icon = <Image src='/img/icons/left-arrow-blue.svg' alt='' width={26} height={26} className={styles.arrow} />;

	// Change the position of the arrow icon depending on the "arrowPosition" prop
	let iconLeft: React.ReactNode;
	let iconRight: React.ReactNode;

	if (arrowPosition === 'left') {
		iconLeft = icon;
	}
	else {
		iconRight = icon;
	}


	/* Define the text
	-------------------------------------------------- */
	let text: React.ReactNode;
	if (size === 'h1') {
		text = <H1>{children}</H1>;
	}
	else if (size === 'h2') {
		text = <H2>{children}</H2>;
	}
	else if (size === 'h3') {
		text = <H3>{children}</H3>;
	}
	else if (size === 'h4') {
		text = <H4>{children}</H4>;
	}
	else {
		text = <Text size={size} inheritWeight={true}>{children}</Text>;
	}


	/* On click of the <NextLink> element
	-------------------------------------------------- */
	function handleClick(event: React.MouseEvent<HTMLAnchorElement>) {
		// If there's no href, prevent this from doing anything
		if (href === '') {
			event.preventDefault();
		}

		// Also call the event handler that could be passed in from the parent
		onClick(event);
	}


	/* Output the component
	-------------------------------------------------- */
	return (
		<NextLink className={classes.join(' ')} id={id} href={href} target={target} onClick={handleClick} {...rest}>
			{iconLeft}
			{text}
			{iconRight}
		</NextLink>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default ArrowButton;

// Types
export type { typedProps as ArrowButtonTypes };
