/*
	Name:
		Component Button

	Description:
		Displays a Button.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		type
			Type: string
			Values: 'primary', 'secondary', 'outline'
			Default: 'primary'
			Description: Define the button style.

		size
			Type: string
			Values: 'l', 'm', 's', 'xs'
			Default: 'm'
			Description: Define the button size.

		href
			Type: string
			Values: Any link
			Default: ''
			Description: Define the href for the button.

		target
			Type: string
			Values: '_blank', '_self', '_parent', '_top'
			Default: '_self'
			Description: Define the target for the button.

		iconName
			Type: string
			Values: Any "Huge Icon" name
			Default: ''
			Description: Select an icon by "Huge Icon" name (https://hugeicons.com/icons).

		iconStyle
			Type: string
			Values: 'stroke', 'duotone', 'solid', 'twotone', 'bulk'
			Default: 'stroke'
			Description: Define the icon style.

		iconType
			Type: string
			Values: 'rounded', 'sharp'
			Default: 'rounded'
			Description: Define the icon type.

		iconPosition
			Type: string
			Values: 'left', 'right'
			Default: 'left'
			Description: Define the icon position.

		...rest
			All other props are passed to <NextLink>.
*/



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import NextLink, { LinkProps } from 'next/link';
import styles from './style.module.css';
import Icon from '../icon';
import Text from '../typography/text';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedProps = {
	id?: string,
	className?: string,
	type?: 'primary' | 'secondary' | 'outline',
	size?: 'l' | 'm' | 's' | 'xs',
	href?: string,
	target?: '_blank' | '_self' | '_parent' | '_top',
	disabled?: boolean,
	iconName?: string,
	iconStyle?: 'stroke' | 'duotone' | 'solid' | 'twotone' | 'bulk',
	iconType?: 'rounded' | 'sharp',
	iconPosition?: 'left' | 'right',
	children?: React.ReactNode
} & LinkProps;

function Button({
	id = '',
	className = '',
	type = 'primary',
	size = 'm',
	href = '',
	target = '_self',
	iconName = '',
	iconStyle = 'stroke',
	iconType = 'rounded',
	iconPosition = 'left',
	children,

	// Support passing in event listeners from the parent
	// This ensures we don't override these as they're also used within this component
	onClick = () => {},

	...rest
}: typedProps) {
	/* Functionality
	---------------------------------------------------------------------------------------------------- */
	/* On click of the <NextLink> element
	-------------------------------------------------- */
	function handleClick(event: React.MouseEvent<HTMLAnchorElement>) {
		// If there's no href, prevent this from doing anything
		if (href === '') {
			event.preventDefault();
		}

		// Also call the event handler that could be passed in from the parent
		onClick(event);
	}



	/* Layout
	---------------------------------------------------------------------------------------------------- */
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_button, className];

	// Type
	if (type) {
		classes.push(styles['type_' + type]);
	}

	// Size
	if (size) {
		classes.push(styles['size_' + size]);
	}


	/* Icon
	-------------------------------------------------- */
	let icon: React.ReactNode;

	// If an icon is set
	if (iconName) {
		// Create the icon
		icon = <Icon name={iconName} style={iconStyle} type={iconType} className={styles.icon} />;

		// Add the position class to the top level of the component
		classes.push(styles['icon_' + iconPosition]);

		// If there's no text, add a special class to handle an icon only button
		if (!children) {
			classes.push(styles.icon_only);
		}
	}


	/* Setup the text size (this exists as the mapping may change)
	-------------------------------------------------- */
	let textSize: 'l' | 'm' | 's' | 'xs';
	if (size === 'l') {
		textSize = 'l';
	}
	else if (size === 'm') {
		textSize = 'm';
	}
	else if (size === 's') {
		textSize = 's';
	}
	else {
		textSize = 'xs';
	}


	/* Output the component
	-------------------------------------------------- */
	return (
		<NextLink className={classes.join(' ')} id={id} href={href} target={target} onClick={handleClick} {...rest}>
			<Text size={textSize} inheritWeight={true} className={styles.text}>{icon}{children}</Text>
		</NextLink>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default Button;

// Types
export type { typedProps as ButtonTypes };
