/*
	Name:
		Component Select

	Description:
		Displays a select form field.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		name
			Type: string
			Values: Any string
			Default: A random unique ID
			Description: Set the name attribute of this select (e.g. <select name='XXX'>)

		state
			Type: string
			Values: 'normal', 'success', 'error'
			Default: ''
			Description: Set the visual state of this component.

		disabled
			Type: boolean
			Values: true, false
			Default: false
			Description: Disable the field.

		label
			Type: string
			Values: Any string
			Default: ''
			Description: Display a field label.

		placeholder
			Type: string
			Values: Any string
			Default: 'Please select'
			Description: Display a placeholder inside this field.

		value
			Type: string
			Values: Any string
			Default: ''
			Description: Define which option is selected by its "value".

		helperText
			Type: string
			Values: Any string
			Default: ''
			Description: Display helper text below this field.

		options
			Type: Array
			Values: An array of objects which define the options.
			Default: ''
			Description: Setup the select options with an array of objects. Example:
			[
				{
					// The label
					label:  'First option',

					// The value
					value:  'first-option'
				},
				...
			]

		...rest
			All other props are passed to <select>.
*/



/* Config
---------------------------------------------------------------------------------------------------- */
"use client";



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import Text from '../../typography/text';
import Icon from '../../icon';
import styles from './style.module.css';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedOptionsObject = {
	label: string,
	value: string
};

type typedProps = {
	id?: string,
	className?: string,
	name?: string,
	state?: 'normal' | 'success' | 'error',
	disabled?: boolean,
	label?: string,
	placeholder?: string,
	value?: string,
	helperText?: string,
	options?: Array<typedOptionsObject>
} & React.ComponentProps<'select'>;

function Select({
	id = '',
	className = '',
	name = '',
	state = 'normal',
	disabled = false,
	label = '',
	placeholder = 'Please select',
	value = '',
	helperText = '',
	options = [],

	// Support passing in event listeners from the parent
	// This ensures we don't override these as they're also used within this component
	onFocus = () => {},
	onChange = () => {},
	onMouseDown = () => {},
	onClick = () => {},
	onBlur = () => {},
	onKeyDown = () => {},

	...rest
}: typedProps) {
	/* Functionality
	---------------------------------------------------------------------------------------------------- */
	/* Create state
	-------------------------------------------------- */
	// Focus state (true, false)
	const [focusState, setFocusState] = React.useState(false);

	// Open state (true, false)
	const [openState, setOpenState] = React.useState(false);

	// Placeholder state (true, false)
	let placeholderStartingState = true;
	if (value) {
		placeholderStartingState = false;
	}
	const [placeholderState, setPlaceholderState] = React.useState(placeholderStartingState);


	/* Create refs to target DOM elements
	-------------------------------------------------- */
	// HTML <select> field
	const fieldRef = React.useRef<HTMLSelectElement>(null);


	/* If there's no name prop generate a unique id
	-------------------------------------------------- */
	const uniqueId = React.useId();
	if (!name) {
		name = uniqueId;
	}


	/* On change of the <select> element
	-------------------------------------------------- */
	function handleChange(event: React.ChangeEvent<HTMLSelectElement>) {
		if (event.currentTarget.value !== '') {
			setPlaceholderState(false);
		}
		else {
			setPlaceholderState(true);
		}

		// Also call the event handler that could be passed in from the parent
		onChange(event);
	}


	/* On click of the <select> element
	-------------------------------------------------- */
	function handleClick(event: React.MouseEvent<HTMLSelectElement>) {
		if (fieldRef.current) {
			const rect = fieldRef.current.getBoundingClientRect();
			const { clientX, clientY } = event;

			const isInComponent =
				clientX >= rect.left &&
				clientX <= rect.right &&
				clientY >= rect.top &&
				clientY <= rect.bottom;

			if (!isInComponent) {
				setOpenState(false);
			}
		}

		// Also call the event handler that could be passed in from the parent
		onClick(event);
	}


	/* On blur of the <select> element
	-------------------------------------------------- */
	function handleBlur(event: React.FocusEvent<HTMLSelectElement>) {
		setFocusState(false);
		setOpenState(false);

		// Also call the event handler that could be passed in from the parent
		onBlur(event);
	}


	/* On focus of the <select> element
	-------------------------------------------------- */
	function handleFocus(event: React.FocusEvent<HTMLSelectElement>) {
		setFocusState(true);

		// Also call the event handler that could be passed in from the parent
		onFocus(event);
	}


	/* On key down of the <select> element
	-------------------------------------------------- */
	function handleKeyDown(event: React.KeyboardEvent<HTMLSelectElement>) {
		if (event.key === 'Enter' || event.keyCode === 13 || event.key === ' ' || event.keyCode === 32) {
			setOpenState(true);
		}

		// Also call the event handler that could be passed in from the parent
		onKeyDown(event);
	}


	/* On mouse down of the <select> element
	-------------------------------------------------- */
	function handleMouseDown(event: React.MouseEvent<HTMLSelectElement>) {
		setOpenState(!openState);

		// Also call the event handler that could be passed in from the parent
		onMouseDown(event);
	}



	/* Layout
	---------------------------------------------------------------------------------------------------- */
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_select, className];


	/* Label
	-------------------------------------------------- */
	let labelOutput: React.ReactNode;
	if (label) {
		labelOutput = (
			<div className={styles.label}>
				<Text size='s' responsive={false} inheritWeight={true}>{label}</Text>
			</div>
		);
	}


	/* Placeholder
	-------------------------------------------------- */
	// Output the placeholder (this is actually a hidden <option>)
	const placeholderOutput = <option value="" disabled className={styles.placeholder}>{placeholder}</option>;


	/* Helper text
	-------------------------------------------------- */
	let helperTextOutput: React.ReactNode;
	if (helperText) {
		helperTextOutput = (
			<div className={styles.helperText}>
				<Text size='xs'>{helperText}</Text>
			</div>
		);
	}


	/* Error text
	-------------------------------------------------- */
	const errorTextOutput = (
		<div className={styles.errorText}>
			<Text size='xs'>Error text</Text>
		</div>
	);


	/* Options
	-------------------------------------------------- */
	const optionsOutput = options.map((option, index) => {
		return (
			<option key={index} value={option.value}>{option.label}</option>
		);
	});


	/* Output the component
	-------------------------------------------------- */
	return (
		<div className={classes.join(' ')} id={id} data-state={state} data-disabled={disabled}>
			{/* Label */}
			{labelOutput}

			<div className={`${styles.fieldContainer} ${styles.hasArrowIcon}`} data-focus={focusState} data-open={openState} data-disabled={disabled} data-placeholder={placeholderState}>
				{/* Field */}
				<select
					name={name}
					defaultValue={value}
					ref={fieldRef}
					disabled={disabled}
					onFocus={handleFocus}
					onChange={handleChange}
					onMouseDown={handleMouseDown}
					onClick={handleClick}
					onBlur={handleBlur}
					onKeyDown={handleKeyDown}
					{...rest}
				>
					{placeholderOutput}
					{optionsOutput}
				</select>

				{/* Arrow icon */}
				<div className={`${styles.icon} ${styles.arrowIcon}`}>
					<Icon name='arrow-down-01' size='s' style='stroke' type='sharp' responsive={false} />
				</div>
			</div>

			{/* Error text */}
			{errorTextOutput}

			{/* Helper text */}
			{helperTextOutput}
		</div>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default Select;

// Types
export type { typedProps as SelectTypes };
