/*
	Name:
		Component Card

	Description:
		Displays a Card.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		type
			Type: string
			Values: 'overview', 'schoolRating', 'chart'
			Default: ''
			Description: Set the type of this card.

		chartColor
			Type: string
			Values: '1', '1_dark', '2', '2_dark', '3', '3_dark', '4', '4_dark', '5', '5_dark', '6', '6_dark', '7', '7_dark', '8', '8_dark'
			Default: '1'
			Description: Only for card type 'chart' - sets the color of the circle.

		schoolRatingFrom
			Type: string
			Values: '', 'Poor', 'Fair', 'Good', 'Great', 'Excellent'
			Default: ''
			Description: Only for card type 'schoolRating' - sets the school rating from value.

		schoolRatingTo
			Type: string
			Values: '', 'Poor', 'Fair', 'Good', 'Great', 'Excellent'
			Default: ''
			Description: Only for card type 'schoolRating' - sets the school rating to value.

		title
			Type: string
			Values: Any string
			Default: ''
			Description: Set the title of this card.

		text
			Type: string
			Values: Any string
			Default: ''
			Description: Set the text of this card.

		...rest
			All other props are passed to <div>.
*/



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import styles from './style.module.css';
import H4 from '../typography/h4';
import Text from '../typography/text';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedProps = {
	id?: string,
	className?: string,
	type?: 'overview' | 'schoolRating' | 'chart',
	chartColor?: '1' | '1_dark' | '2' | '2_dark' | '3' | '3_dark' | '4' | '4_dark' | '5' | '5_dark' | '6' | '6_dark' | '7' | '7_dark' | '8' | '8_dark',
	schoolRatingFrom?: '' | 'Poor' | 'Fair' | 'Good' | 'Great' | 'Excellent',
	schoolRatingTo?: '' | 'Poor' | 'Fair' | 'Good' | 'Great' | 'Excellent',
	title?: string,
	text?: string
} & React.ComponentProps<'div'>;

function Card({
	id = '',
	className = '',
	type = 'overview',
	chartColor = '1',
	schoolRatingFrom = '',
	schoolRatingTo = '',
	title = '',
	text = '',
	...rest
}: typedProps) {
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_card, className];

	// Type
	if (type) {
		classes.push(styles['type_' + type]);
	}


	/* Create a ref for the chart color
	-------------------------------------------------- */
	const chartColorRef = React.useRef<HTMLInputElement>(null);


	/* Title
	-------------------------------------------------- */
	let titleOutput: React.ReactNode;


	/* Overview Card
	------------------------- */
	if (type === 'overview') {
		titleOutput = (
			<H4 className={styles.title} >{title}</H4>
		);
	}


	/* School Rating Card
	------------------------- */
	else if (type === 'schoolRating') {
		let schoolRatingFromOutput: React.ReactNode;
		if (schoolRatingFrom !== '') {
			schoolRatingFromOutput = <span className={styles['schoolRating_' + schoolRatingFrom.toLowerCase()]}>{schoolRatingFrom}</span>;
		}

		let schoolRatingJoinOutput: React.ReactNode;
		if (schoolRatingFrom !== '' && schoolRatingTo !== '') {
			schoolRatingJoinOutput = <span className={styles.schoolRating_join}>&nbsp;to&nbsp;</span>;
		}

		let schoolRatingToOutput: React.ReactNode;
		if (schoolRatingTo !== '') {
			schoolRatingToOutput = <span className={styles['schoolRating_' + schoolRatingTo.toLowerCase()]}>{schoolRatingTo}</span>;
		}

		titleOutput = (
			<>
				<H4 className={styles.schoolRatingContainer}>
					{schoolRatingFromOutput}
					{schoolRatingJoinOutput}
					{schoolRatingToOutput}
				</H4>
				<H4 className={styles.title}>{title}</H4>
			</>
		);
	}


	/* Chart Card
	------------------------- */
	else if (type === 'chart') {
		titleOutput = (
			<>
				<div className={`${styles.chartColor} ${styles['chartColor_' + chartColor]}`} ref={chartColorRef} />
				<H4 className={styles.title}>{title}</H4>
			</>
		);
	}


	/* Output the component
	-------------------------------------------------- */
	return (
		<div className={classes.join(' ')} id={id} {...rest}>
			<div className={styles.inner}>
				<div className={styles.titleContainer}>{titleOutput}</div>
				<Text className={styles.text} size='s'>{text}</Text>
			</div>
		</div>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default Card;

// Types
export type { typedProps as CardTypes };
